// ─── Toast ────────────────────────────────────────────────────────────────────
function Toast({ msg, onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 2500); return () => clearTimeout(t); }, []);
  return <div className="toast">{msg}</div>;
}

// ─── Spinner ─────────────────────────────────────────────────────────────────
function Loading({ text = "Carregando..." }) {
  return <div className="loading"><div className="spinner" />{text}</div>;
}

// ─── Modal ────────────────────────────────────────────────────────────────────
function Modal({ title, onClose, children }) {
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"1.25rem" }}>
          <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:"1.3rem", margin:0 }}>{title}</h3>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>✕</button>
        </div>
        {children}
      </div>
    </div>
  );
}

function EmptyState({ icon, text, action }) {
  return (
    <div className="empty-state">
      <div className="empty-icon">{icon}</div>
      <div style={{ fontSize:"0.9rem" }}>{text}</div>
      {action && <div style={{ marginTop:"1rem" }}>{action}</div>}
    </div>
  );
}

