      <div className="login-box">
        <div style={{ marginBottom:"0.5rem" }}>
          <img src={LOGO_LIGHT} alt="Prêmio Lúmen" style={{ maxWidth:220, objectFit:"contain" }} />
        </div>
        <div className="login-sub">Sistema de Avaliação — Painel Admin</div>
        <div className="form-group">
          <label className="form-label">Senha de Administrador</label>
          <input className="form-input" type="password" value={pw} onChange={e=>{setPw(e.target.value);setErr("");}} onKeyDown={e=>e.key==="Enter"&&handle()} placeholder="Digite a senha..." autoFocus />
          {err && <div className="login-error">{err}</div>}
        </div>
        <button className="btn btn-primary" style={{ width:"100%" }} onClick={handle}>Entrar</button>
      </div>
